public class ScheduledExecutorService{

    static PriorityQueue<ScheduledTask> queue;
    static ExecutorService executor;

    public ScheduledExecutorService(){
        queue = new PriorityQueue<>();
        executor = Executors.newFixedThreadPool(Runtime.getRuntime().availableProcessors());
    }

    public void schedule(Runnable command, long delay, ChronoUnit unit) {
        ScheduledTask t1 = new ScheduledTask(command, LocalDateTime.now().plus(delay, unit));
        queue.add(t1);
    }

    public void scheduleAtFixedRate(Runnable command, long initialDelay, long period, ChronoUnit unit) {
        ScheduledTask t1 = new ScheduledTask(command, LocalDateTime.now().plus(initialDelay, unit), unit, period, TaskType.FIXEDRATE);
        queue.add(t1);
    }

    public void scheduleWithFixedDelay(Runnable command, long initialDelay, long delay, ChronoUnit unit) {
        ScheduledTask t1 = new ScheduledTask(command, LocalDateTime.now().plus(initialDelay, unit), unit, delay, TaskType.FIXEDDELAY);
        queue.add(t1);
    }

    void execution() throws InterruptedException {
        while (!queue.isEmpty()){
            boolean processingNeeded = false;
            ScheduledTask task = queue.peek();
            if (task.getExecutionTime().isBefore(LocalDateTime.now())) processingNeeded = true;
            else {
                Duration duration = Duration.between(LocalDateTime.now(), task.getExecutionTime());
                if (duration.getSeconds() < 1) processingNeeded = true;
            }
            if (processingNeeded){
                task = queue.poll();
                if(task != null && task.getType() != null && task.getType().equals(TaskType.FIXEDRATE)){
                    ScheduledTask t1 = new ScheduledTask(task.getTask(), task.getExecutionTime().plus(task.getTime(), task.getUnit()),
                            task.getUnit(), task.getTime(), TaskType.FIXEDRATE);
                    queue.add(t1);
                }
                executor.submit(task.getTask());
                if(task != null && task.getType() != null &&task.getType().equals(TaskType.FIXEDDELAY)){
                    ScheduledTask t1 = new ScheduledTask(task.getTask(), LocalDateTime.now().plus(task.getTime(), task.getUnit()),
                            task.getUnit(), task.getTime(), TaskType.FIXEDDELAY);
                    queue.add(t1);
                }
            }
            Thread.sleep(500);
        }
    }
}


public class ScheduledTask implements Comparator {

    public ScheduledTask(Runnable task, LocalDateTime executionTime) {
        this.task = task;
        this.executionTime = executionTime;
    }

    public Runnable getTask() {
        return task;
    }

    public LocalDateTime getExecutionTime() {
        return executionTime;
    }

    private Runnable task;

    public ScheduledTask(Runnable task, LocalDateTime executionTime, ChronoUnit unit, long time) {
        this.task = task;
        this.executionTime = executionTime;
        this.unit = unit;
        this.time = time;
    }

    private LocalDateTime executionTime;

    public ChronoUnit getUnit() {
        return unit;
    }

    public long getTime() {
        return time;
    }

    private ChronoUnit unit;
    private long time;

    public ScheduledTask(Runnable task, LocalDateTime executionTime, ChronoUnit unit, long time, TaskType type) {
        this.task = task;
        this.executionTime = executionTime;
        this.unit = unit;
        this.time = time;
        this.type = type;
    }

    public TaskType getType() {
        return type;
    }

    private TaskType type;

    @Override
    public int compare(Object o1, Object o2) {
        ScheduledTask t1 = (ScheduledTask)o1;
        ScheduledTask t2 = (ScheduledTask)o1;
        return t1.getExecutionTime().compareTo(t2.getExecutionTime());
    }
}

public enum TaskType {
    NONE,
    FIXEDRATE,
    FIXEDDELAY
